     1|/**
     2| * IVX Owner AI Request Control — idempotency, status, retry, and cancel endpoints.
     3| *
     4| * POST   /api/ivx/owner-ai/request                  — idempotent AI request
     5| * GET    /api/ivx/owner-ai/request/:traceId/status  — query request status
     6| * POST   /api/ivx/owner-ai/request/:traceId/retry   — retry a failed request
     7| * POST   /api/ivx/owner-ai/request/:traceId/cancel  — cancel an in-flight request
     8| *
     9| * The same idempotency key never creates duplicate AI replies.
    10| */
    11|
    12|import { ownerOnlyJson, ownerOnlyOptions, assertIVXOwnerOnly } from './owner-only';
    13|
    14|interface RequestRecord {
    15|  traceId: string;
    16|  requestId: string;
    17|  conversationId: string | null;
    18|  messageId: string;
    19|  idempotencyKey: string;
    20|  status: 'pending' | 'in_flight' | 'completed' | 'failed' | 'cancelled';
    21|  retryCount: number;
    22|  providerRequestId: string | null;
    23|  startedAt: string;
    24|  completedAt: string | null;
    25|  terminalResult: {
    26|    answer: string | null;
    27|    error: string | null;
    28|    httpStatus: number | null;
    29|  } | null;
    30|  structuredError: {
    31|    code: string;
    32|    message: string;
    33|    checkpoint: string | null;
    34|  } | null;
    35|}
    36|
    37|// In-memory store (persisted to Redis in production via the worker)
    38|const requestStore = new Map<string, RequestRecord>();
    39|const idempotencyIndex = new Map<string, string>(); // idempotencyKey → traceId
    40|
    41|const MAX_STORE_SIZE = 1000;
    42|
    43|function pruneStore(): void {
    44|  if (requestStore.size > MAX_STORE_SIZE) {
    45|    const oldestKeys = Array.from(requestStore.keys())
    46|      .slice(0, requestStore.size - MAX_STORE_SIZE);
    47|    for (const key of oldestKeys) {
    48|      const record = requestStore.get(key);
    49|      if (record) {
    50|        idempotencyIndex.delete(record.idempotencyKey);
    51|      }
    52|      requestStore.delete(key);
    53|    }
    54|  }
    55|}
    56|
    57|function generateRequestId(): string {
    58|  return `req-${Date.now()}-${Math.random().toString(36).slice(2, 10)}`;
    59|}
    60|
    61|function generateTraceId(): string {
    62|  return `ivx-req-${Date.now()}-${Math.random().toString(36).slice(2, 10)}`;
    63|}
    64|
    65|function generateIdempotencyKey(conversationId: string, message: string): string {
    66|  let hash = 0;
    67|  const input = `${conversationId}:${message}`;
    68|  for (let i = 0; i < input.length; i++) {
    69|    const char = input.charCodeAt(i);
    70|    hash = ((hash << 5) - hash + char) | 0;
    71|  }
    72|  return `idemp-${Math.abs(hash).toString(36)}-${input.length.toString(36)}`;
    73|}
    74|
    75|export function handleIVXOwnerAIRequestControlOptions(): Response {
    76|  return ownerOnlyOptions();
    77|}
    78|
    79|interface RequestControlBody {
    80|  message: string;
    81|  conversationId?: string | null;
    82|  messageId?: string;
    83|  traceId?: string;
    84|  idempotencyKey?: string;
