    87|
    88|/**
    89| * POST /api/ivx/owner-ai/request
    90| * Idempotent AI request: if the same idempotency key was already used,
    91| * return the cached result instead of creating a duplicate.
    92| */
    93|export async function handleIVXOwnerAIRequestCreate(rawRequest: Request): Promise<Response> {
    94|  let authContext;
    95|  try {
    96|    authContext = await assertIVXOwnerOnly(rawRequest);
    97|  } catch (authErr) {
    98|    const status = authErr instanceof Error && 'status' in authErr
