   100|      : 401;
   101|    return ownerOnlyJson({ error: 'Authentication required' }, status);
   102|  }
   103|
   104|  let body: RequestControlBody;
   105|  try {
   106|    body = await rawRequest.json() as RequestControlBody;
   107|  } catch {
   108|    return ownerOnlyJson({ error: 'Invalid JSON body' }, 400);
   109|  }
   110|
   111|  if (!body.message || typeof body.message !== 'string' || body.message.trim().length === 0) {
   112|    return ownerOnlyJson({ error: 'message is required' }, 400);
   113|  }
   114|
   115|  const conversationId = body.conversationId ?? null;
   116|  const messageId = body.messageId ?? `msg-${Date.now()}`;
   117|  const traceId = body.traceId ?? generateTraceId();
   118|  const idempotencyKey = body.idempotencyKey ?? generateIdempotencyKey(conversationId ?? 'default', body.message);
   119|
   120|  // Idempotency check: if this key was already used, return the cached result
   121|  const existingTraceId = idempotencyIndex.get(idempotencyKey);
   122|  if (existingTraceId) {
   123|    const existing = requestStore.get(existingTraceId);
   124|    if (existing && (existing.status === 'completed' || existing.status === 'in_flight')) {
   125|      return ownerOnlyJson({
   126|        traceId: existing.traceId,
   127|        requestId: existing.requestId,
   128|        status: existing.status,
   129|        idempotencyKey: existing.idempotencyKey,
   130|        duplicate: true,
   131|        result: existing.terminalResult,
   132|        message: 'Idempotent replay: returning cached result for this idempotency key.',
   133|      }, 200);
   134|    }
   135|  }
   136|
   137|  // Create new request record
   138|  const requestId = generateRequestId();
   139|  const record: RequestRecord = {
   140|    traceId,
   141|    requestId,
   142|    conversationId,
   143|    messageId,
   144|    idempotencyKey,
   145|    status: 'pending',
   146|    retryCount: 0,
   147|    providerRequestId: null,
   148|    startedAt: new Date().toISOString(),
   149|    completedAt: null,
   150|    terminalResult: null,
   151|    structuredError: null,
   152|  };
   153|
   154|  requestStore.set(traceId, record);
   155|  idempotencyIndex.set(idempotencyKey, traceId);
   156|  pruneStore();
   157|
   158|  return ownerOnlyJson({
   159|    traceId,
   160|    requestId,
   161|    status: 'pending',
   162|    idempotencyKey,
   163|    duplicate: false,
   164|    message: 'Request accepted. Use GET /request/:traceId/status to poll.',
   165|  }, 202);
   166|}
