   168|/**
   169| * GET /api/ivx/owner-ai/request/:traceId/status
   170| * Query the status of a request by traceId.
   171| */
   172|export async function handleIVXOwnerAIRequestStatus(rawRequest: Request, traceId: string): Promise<Response> {
   173|  try {
   174|    await assertIVXOwnerOnly(rawRequest);
   175|  } catch (authErr) {
