    10|export type IVXOwnerMutationApprovalProof = {
    11|  ownerSessionDetected: boolean;
    12|  bearerAccepted: boolean;
    13|  ownerVerified: boolean;
    14|  ownerEmailMatched: boolean;
    15|  ownerEmailMasked: string | null;
