    31|
    32|export class IVXOwnerApprovalError extends Error {
    33|  readonly status: number;
    34|  readonly proof: IVXOwnerMutationApprovalProof;
    35|
    36|  constructor(message: string, status: number, proof: IVXOwnerMutationApprovalProof) {
    37|    super(message);
    38|    this.name = 'IVXOwnerApprovalError';
    39|    this.status = status;
    40|    this.proof = proof;
    41|  }
