    43|
    44|const OWNER_ONLY_HEADERS = {
    45|  'Content-Type': 'application/json',
    46|  'Cache-Control': 'no-store',
    47|  'Access-Control-Allow-Origin': 'https://ivxholding.com',
    48|  'Access-Control-Allow-Headers': 'Content-Type, Authorization',
    49|  'Access-Control-Allow-Methods': 'GET, HEAD, POST, OPTIONS',
    50|} as const;
    51|
    52|/**
    53| * Hard ceiling on a single owner-AI JSON response body. The upstream proxy/host
    54| * truncates very large bodies mid-stream, which produces an invalid-JSON reply
    55| * the client "cannot read" (the "temporary backend formatting issue" the owner
    56| * saw). We keep responses safely under that ceiling.
    57| */
    58|const OWNER_ONLY_MAX_RESPONSE_BYTES = 900_000;
    59|
    60|/**
    61| * Serialize an owner response to JSON that the client can ALWAYS parse.
    62| *
    63| * Guarantees, in order:
    64| *   1. JSON.stringify never throws (circular refs / BigInt / bad getters fall
    65| *      back to a minimal canonical envelope instead of a 500 / empty body).
    66| *   2. The body never exceeds OWNER_ONLY_MAX_RESPONSE_BYTES — when it would,
    67| *      heavy diagnostic-only fields are dropped and the visible `answer` is
    68| *      safely truncated, preserving the canonical contract
    69| *      (requestId/conversationId/answer/model/status).
    70| */
    71|function serializeOwnerOnlyPayload(payload: Record<string, unknown>): string {
    72|  let body: string;
    73|  try {
    74|    body = JSON.stringify(payload);
    75|  } catch (error) {
    76|    return JSON.stringify(buildMinimalOwnerEnvelope(payload, error));
    77|  }
    78|
    79|  if (body.length <= OWNER_ONLY_MAX_RESPONSE_BYTES) {
    80|    return body;
    81|  }
    82|
    83|  // Oversized: strip diagnostic-only fields that are never required to render a
    84|  // reply, then re-serialize. `answer` is preserved (truncated if needed).
    85|  const slim: Record<string, unknown> = { ...payload };
    86|  for (const heavyField of ['toolOutputs', 'toolOutput', 'toolInput', 'runtimeV2', 'routerDebug', 'diagnostics', 'providerError']) {
    87|    delete slim[heavyField];
    88|  }
    89|  if (typeof slim.answer === 'string' && slim.answer.length > 40_000) {
    90|    slim.answer = `${slim.answer.slice(0, 40_000)}\n\n…[truncated for transport — full result preserved server-side]`;
    91|  }
    92|  slim.responseTruncated = true;
    93|
    94|  try {
    95|    const slimBody = JSON.stringify(slim);
    96|    if (slimBody.length <= OWNER_ONLY_MAX_RESPONSE_BYTES) {
    97|      return slimBody;
    98|    }
    99|  } catch {
   100|    // fall through to minimal envelope
   101|  }
   102|  return JSON.stringify(buildMinimalOwnerEnvelope(payload, null));
   103|}
   104|
   105|function buildMinimalOwnerEnvelope(payload: Record<string, unknown>, error: unknown): Record<string, unknown> {
   106|  const reason = error instanceof Error ? error.message : null;
   107|  const answer = typeof payload.answer === 'string' && payload.answer.trim()
   108|    ? payload.answer.slice(0, 20_000)
   109|    : 'The IVX Owner AI completed, but its full response was too large or could not be serialized. The result was preserved server-side — please resend.';
   110|  return {
   111|    requestId: typeof payload.requestId === 'string' ? payload.requestId : `ivx-${Date.now()}`,
   112|    conversationId: typeof payload.conversationId === 'string' ? payload.conversationId : 'ivx-owner-ai',
   113|    answer,
   114|    model: typeof payload.model === 'string' ? payload.model : 'ivx_owner_ai_safe_envelope',
   115|    status: payload.status === 'error' ? 'error' : 'ok',
   116|    source: 'local_app_brain',
   117|    responseTruncated: true,
   118|    serializationFallback: reason ? `serialize_failed: ${reason}`.slice(0, 240) : 'serialize_size_guard',
   119|  };
   120|}
   121|
   122|export function ownerOnlyJson(payload: Record<string, unknown>, status: number = 200): Response {
   123|  return new Response(serializeOwnerOnlyPayload(payload), {
   124|    status,
   125|    headers: OWNER_ONLY_HEADERS,
   126|  });
   127|}
   128|
   129|export function ownerOnlyOptions(): Response {
   130|  return new Response(null, {
   131|    status: 204,
   132|    headers: OWNER_ONLY_HEADERS,
